data.value:
decimal sumFemaleTransfer = 0;
decimal sumFemaleMort = 0;
decimal sumFemaleCulls = 0;
decimal sumFemaleError = 0;
decimal sumMaleMort = 0;
decimal sumMaleSelection = 0;
decimal sumMaleCulls = 0;
decimal sumMaleError = 0;
decimal sumMaleTransfer = 0;
decimal totalLayFemaleTransfer = 0;
decimal totalLayMaleMort = 0;
decimal totalLayMaleTransfer = 0;
decimal totalLayFemaleMort = 0;
decimal totalRearFemaleCulls = 0;
decimal totalRearFemaleError = 0;

private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // Accumulate values
    sumFemaleMort += Convert.ToDecimal(GetCurrentColumnValue("RearFemaleMort") ?? 0);
    sumFemaleCulls += Convert.ToDecimal(GetCurrentColumnValue("RearFemaleCulls") ?? 0);
    sumFemaleError += Convert.ToDecimal(GetCurrentColumnValue("RearFemaleError") ?? 0);
    sumFemaleTransfer += Convert.ToDecimal(GetCurrentColumnValue("RearFemaleTransfer") ?? 0);

    // Accumulate male values
    sumMaleMort += Convert.ToDecimal(GetCurrentColumnValue("RearMaleMort") ?? 0);
    sumMaleSelection += Convert.ToDecimal(GetCurrentColumnValue("MaleSelection") ?? 0);
    sumMaleCulls += Convert.ToDecimal(GetCurrentColumnValue("RearMaleCulls") ?? 0);
    sumMaleError += Convert.ToDecimal(GetCurrentColumnValue("RearMaleError") ?? 0);
    sumMaleTransfer += Convert.ToDecimal(GetCurrentColumnValue("RearMaleTransfer") ?? 0);

    // Accumulate sums from each detail row
    totalLayFemaleTransfer += Convert.ToDecimal(GetCurrentColumnValue("LayFemaleTransfer") ?? 0);
    totalLayFemaleMort += Convert.ToDecimal(GetCurrentColumnValue("LayFemaleMort") ?? 0);
    totalLayMaleMort += Convert.ToDecimal(GetCurrentColumnValue("LayMaleMort") ?? 0);
    totalLayMaleTransfer += Convert.ToDecimal(GetCurrentColumnValue("LayMaleTransfer") ?? 0);

    totalRearFemaleCulls += Convert.ToDecimal(GetCurrentColumnValue("RearFemaleCulls") ?? 0);
    totalRearFemaleError += Convert.ToDecimal(GetCurrentColumnValue("RearFemaleError") ?? 0);
}

private void xrTableCell56_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     XRTableCell cell = sender as XRTableCell;

    // Get current FemaleTransBalance (should be total/group value)
    decimal femaleTransBalance = Convert.ToDecimal(GetCurrentColumnValue("FemaleTransBalance") ?? 0);

    // Calculate result
    decimal totalDeductions = sumFemaleMort + sumFemaleCulls + sumFemaleError + sumFemaleTransfer;
    decimal result = femaleTransBalance - totalDeductions;

    cell.Text = result.ToString("N0");
}

private void xrTableCell57_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     XRTableCell cell = sender as XRTableCell;

    // Get current MaleTransBalance (should be total/group value)
    decimal maleTransBalance = Convert.ToDecimal(GetCurrentColumnValue("MaleTransBalance") ?? 0);

    // Calculate result
    decimal totalDeductions = sumMaleMort + sumMaleSelection + sumMaleCulls + sumMaleError + sumMaleTransfer;
    decimal result = maleTransBalance - totalDeductions;

    cell.Text = result.ToString("N0");
}

private void xrTableCell58_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     XRTableCell cell = sender as XRTableCell;

    // Apply equation to the SUMS: Σ(LayFemaleTransfer) - Σ(LayMaleMort)
    decimal result = totalLayFemaleTransfer - totalLayMaleMort;

    cell.Text = result.ToString("N0"); // Whole number format
        }

