    decimal result = totalLayMaleTransfer - totalLayMaleMort;

    cell.Text = result.ToString("N0"); // Whole number format

}

private void xrTableCell62_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     XRTableCell cell = sender as XRTableCell;

    // Calculate total: Σ(RearFemaleMort) + Σ(LayFemaleMort)
    decimal totalFemaleMort = sumFemaleMort + totalLayFemaleMort;

    cell.Text = totalFemaleMort.ToString("N0"); // Whole number format
}

