}

private void xrTableCell65_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
        XRTableCell cell = sender as XRTableCell;

    // Get FemaleTransBalance value
    decimal femaleTransBalance = Convert.ToDecimal(GetCurrentColumnValue("FemaleTransBalance") ?? 0);
     // Apply formula: FemaleTransBalance - (TotalErrorFemale + TotalFemaleCulls + TotalMortFemale)
    decimal totalDeductions = sumFemaleError + sumFemaleCulls + sumFemaleMort ;
    decimal result = femaleTransBalance - totalDeductions;

    cell.Text = result.ToString("N0");
}

