private void xrTableCell70_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     XRTableCell cell = sender as XRTableCell;

    decimal MaleTransBalance = Convert.ToDecimal(GetCurrentColumnValue("MaleTransBalance") ?? 0);
    decimal result = MaleTransBalance - (sumMaleCulls  + sumMaleError + sumMaleMort  + totalLayMaleMort ) ;

    cell.Text = result.ToString("N0");

}
